B.Q1=new A.ch("grammar_1","Edilgen \xc7at\u0131","Havac\u0131l\u0131k g\xf6revlerinin nas\u0131l anlat\u0131ld\u0131\u011f\u0131","grammar","\ud83d\udd27",B.UN)
B.Qb=new A.V(B.aj,"Modal fiiller zorunluluk ve izin ifade eder",'Modal fiiller, **zorunluluk derecelerini** ifade etti\u011fi i\xe7in havac\u0131l\u0131k \u0130ngilizcesinde son derece \xf6nemlidir. "must" ile "should" aras\u0131ndaki fark g\xfcvenlik sonu\xe7lar\u0131 do\u011furabilir.\n\n**must** = zorunlu (yasal gereklilik)\n**should** = \xf6nerilen (en iyi uygulama)\n**may** = izin verilen (serbest)\n**can** = yetenek / teorik olas\u0131l\u0131k',null,null,null)
B.QP=new A.V(B.f0,"Modal g\xfc\xe7 skalas\u0131",null,null,B.rh,null)
B.Sj=new A.V(B.B,"Modal + Fiil Yap\u0131s\u0131",'**Rule:** Modal verb + **base infinitive** (no "to", no "-s", no "-ing")\n\n\u2713 The pilot **must check** the fuel level.\n\u2717 The pilot must **checks** / must **checking** / must **to check**\n\n**With passive:**\nModal + **be** + past participle\n\u2713 The engine **must be shut down** before maintenance.\n\u2713 Parts **should be inspected** visually.',null,null,null)
B.L1=new A.aJ("The engine must be shut down before any maintenance work begins.","Herhangi bir bak\u0131m \xe7al\u0131\u015fmas\u0131 ba\u015flamadan \xf6nce motor kapat\u0131lmal\u0131d\u0131r.","must be shut down")
B.M8=new A.aJ("Technicians should wear protective equipment when handling fuel.","Teknisyenler yak\u0131t ile \xe7al\u0131\u015f\u0131rken koruyucu ekipman takmal\u0131d\u0131r.","should wear")
B.LA=new A.aJ("The aircraft may depart after all checks are completed.","T\xfcm kontroller tamamland\u0131ktan sonra u\xe7ak kalkabilir.","may depart")
B.Lx=new A.aJ("Contaminated parts must not be reinstalled without inspection.","Kirlenmi\u015f par\xe7alar incelenmeden yeniden tak\u0131lmamal\u0131d\u0131r.","must not be reinstalled")
B.VU=s([B.L1,B.M8,B.LA,B.Lx],t.l)
B.Qy=new A.V(B.ak,"Ba\u011flamda Modal Fiiller",null,B.VU,null,null)
B.So=new A.V(B.al,"\u2708\ufe0f S\u0131nav \u0130pucu",'Modal sorular\u0131nda yayg\u0131n tuzaklar:\n\u2022 "must checking" \u2192 YANLI\u015e (modal + yal\u0131n fiil, -ing de\u011fil)\n\u2022 "should to inspect" \u2192 YANLI\u015e (modal sonras\u0131nda "to" gelmez)\n\u2022 "must performed" \u2192 YANLI\u015e (edilgen i\xe7in "be" gerekli: must **be** performed)\n\nModal fiil + bo\u015fluk g\xf6r\xfcnce sor: etken mi yoksa edilgen anlam m\u0131 gerekiyor?',null,null,null)
