B.R7=new A.V(B.aj,"Teknik kelime bilgisi neden \xf6nemlidir",'Havac\u0131l\u0131k s\u0131navlar\u0131, kesin teknik terimleri anlama ve kullanma becerinizi \xf6l\xe7er. Bir teknisyenin **aileron** yerine "u\xe7a\u011f\u0131 kald\u0131ran \u015fey" demesi hem profesyonellikten uzak hem de tehlikelidir.\n\nBu ders, u\xe7ak sistemine g\xf6re grupland\u0131r\u0131lm\u0131\u015f en s\u0131k s\u0131nanan bile\u015fenleri kapsar.',null,null,null)
B.Sx=new A.V(B.B,"\ud83d\udee9\ufe0f U\xe7u\u015f Kontrol Y\xfczeyleri","**Ailerons** \u2014 on the wings; control roll (bank left/right)\n**Elevator** \u2014 on the horizontal stabilizer; controls pitch (nose up/down)\n**Rudder** \u2014 on the vertical stabilizer; controls yaw (nose left/right)\n**Flaps** \u2014 on wing trailing edge; increase lift and drag during takeoff/landing\n**Spoilers** \u2014 on wings; reduce lift, increase drag, assist in roll control",null,null,null)
B.S7=new A.V(B.B,"\u2699\ufe0f Motor & Yak\u0131t Sistemleri","**Turbine engine** \u2014 compressor \u2192 combustion chamber \u2192 turbine \u2192 nozzle\n**HP fuel shutoff valve** \u2014 high-pressure fuel control valve\n**Fuel manifold** \u2014 distributes fuel to combustion chambers\n**Gearbox** \u2014 transfers power between engine components\n**Nacelle** \u2014 streamlined housing enclosing the engine",null,null,null)
B.Su=new A.V(B.B,"\ud83d\udd27 Hidrolik & \u0130ni\u015f Tak\u0131m\u0131","**Hydraulic actuator** \u2014 converts hydraulic pressure to mechanical movement\n**Hydraulic pump** \u2014 pressurizes hydraulic fluid\n**Landing gear strut** \u2014 shock-absorbing leg of landing gear\n**Torque link** \u2014 scissors linkage preventing wheel rotation on strut\n**Brake assembly** \u2014 disc brakes on main landing gear wheels",null,null,null)
B.KQ=new A.aJ("The ailerons deflect differentially to produce a rolling moment.","Eleronlar, yuvarlanma momenti \xfcretmek i\xe7in farkl\u0131 a\xe7\u0131larda sapma yapar.","ailerons")
B.Lj=new A.aJ(u.d,"Hidrolik pompa, motor taraf\u0131ndan di\u015fli kutusu arac\u0131l\u0131\u011f\u0131yla tahrik edilir.","hydraulic pump")
