B.SS=new A.V(B.aj,"G\xfcvenlik ekipman\u0131 adlar\u0131 kesin olmal\u0131d\u0131r","G\xfcvenlik ekipman\u0131 i\xe7in yanl\u0131\u015f isimler kullanmak tehlikeli yanl\u0131\u015f anla\u015f\u0131lmalara yol a\xe7abilir. S\u0131nav sorular\u0131 ekipman adlar\u0131, i\u015flevleri ve bunlarla kullan\u0131lan fiiller hakk\u0131nda kesin bilgi \xf6l\xe7er.\n\nBu ders, t\xfcm havac\u0131l\u0131k rolleri i\xe7in en s\u0131k s\u0131nanan g\xfcvenlik ekipman\u0131 terimlerini kapsar.",null,null,null)
B.Qt=new A.V(B.B,"\ud83d\udee1\ufe0f Kabin G\xfcvenlik Ekipmanlar\u0131","**Portable oxygen unit** \u2014 portable O\u2082 bottle for crew use\n**Drop-down oxygen mask** \u2014 passenger masks, auto-deploys above 10,000 ft cabin alt\n**Life vest / Life jacket** \u2014 under-seat flotation device\n**Emergency exit** \u2014 floor-level lighting marks the path\n**Escape slide** \u2014 inflatable slide for rapid evacuation\n**Fire extinguisher** \u2014 Halon type in cockpit, water/CO\u2082 in cabin\n**ELT** \u2014 Emergency Locator Transmitter (activates on impact)",null,null,null)
B.Sb=new A.V(B.B,"\ud83d\udd27 Teknik G\xfcvenlik Ekipmanlar\u0131","**Circuit breaker (CB)** \u2014 protects electrical circuits from overload\n**Fire detector** \u2014 senses smoke/heat in engine, APU, cargo compartment\n**Fire suppression system** \u2014 discharges extinguisher agent into engine nacelle\n**Overheat detector** \u2014 warns of bleed air duct overheating\n**TCAS** \u2014 Traffic Collision Avoidance System\n**GPWS/EGPWS** \u2014 Ground Proximity Warning System",null,null,null)
B.La=new A.aJ("Oxygen masks will drop down automatically if cabin altitude exceeds 10,000 feet.","Kabin irtifas\u0131 10.000 fiti a\u015farsa oksijen maskeleri otomatik olarak d\xfc\u015fer.","drop down automatically")
B.M2=new A.aJ("The fire suppression system discharged successfully into the engine nacelle.","Yang\u0131n bast\u0131rma sistemi motor kovan\u0131na ba\u015far\u0131yla de\u015farj edildi.","fire suppression system")
B.Lh=new A.aJ("All cabin crew must demonstrate the life vest donning procedure to passengers.","T\xfcm kabin ekibi yolculara can yele\u011fi giyinme prosed\xfcr\xfcn\xfc g\xf6stermelidir.","donning procedure")
