B.Sl=new A.V(B.aj,"Kontrol listeleri sabit dil kal\u0131plar\u0131n\u0131 takip eder","Havac\u0131l\u0131k kontrol listeleri son derece standartla\u015ft\u0131r\u0131lm\u0131\u015f bir dil yap\u0131s\u0131 kullan\u0131r. G\xfcnl\xfck \u0130ngilizcenin aksine, kontrol listesi dili **s\u0131k\u0131\u015ft\u0131r\u0131lm\u0131\u015f ve kesin**tir \u2014 her kelime do\u011fruluk ve k\u0131sal\u0131k i\xe7in se\xe7ilmi\u015ftir.\n\nBo\u015fluk doldurma sorular\u0131, her kontrol listesi \xf6\u011fesi i\xe7in do\u011fru teknik terim veya ifadeyi bilip bilmedi\u011finizi s\u0131nar.",null,null,null)
B.QN=new A.V(B.B,"\ud83d\udccb Kontrol Listesi Dil Kal\u0131plar\u0131",'Kontrol listeleri \xfc\xe7 ana kal\u0131p kullan\u0131r:\n\n**Soru / Yan\u0131t (Challenge / Response):**\n"PARKING BRAKE \u2014 **SET**"\n"SEAT BELTS \u2014 **ON**"\n"FUEL QUANTITY \u2014 **CHECKED**"\n\n**Eylem maddeleri:**\n"\u2026\u2026\u2026\u2026\u2026 the altimeters to QNH"\n"\u2026\u2026\u2026\u2026\u2026 the ILS frequency and course"\n"\u2026\u2026\u2026\u2026\u2026 the transponder to 2000"\n\nYayg\u0131n eylem fiilleri: **set, check, confirm, select, arm, position, verify, engage**',null,null,null)
