B.Qx=new A.V(B.aj,"Ko\u015ful c\xfcmleleri neden-sonu\xe7 ili\u015fkisi kurar","Havac\u0131l\u0131k prosed\xfcrleri \xe7o\u011funlukla belirli bir ko\u015ful ger\xe7ekle\u015fti\u011finde ne olaca\u011f\u0131n\u0131 anlat\u0131r. Acil durum kontrol listeleri, operasyon k\u0131lavuzlar\u0131 ve s\u0131nav sorular\u0131 ko\u015ful c\xfcmlelerine yo\u011fun bi\xe7imde dayan\u0131r.\n\nHangi ko\u015ful c\xfcmlesi tipini kullanaca\u011f\u0131n\u0131z, durumun **ger\xe7ek/olas\u0131** m\u0131 yoksa **varsay\u0131msal/imk\xe2ns\u0131z** m\u0131 oldu\u011funa g\xf6re belirlenir.",null,null,null)
B.QR=new A.V(B.f0,"Bir bak\u0131\u015fta ko\u015ful tipleri",null,null,B.ri,null)
B.RV=new A.V(B.B,"\xdc\xe7 Ana Tip",'**Type 1 \u2014 Real/Possible (present/future)**\nIf + present simple, will/can/must + base verb\n\u2192 "If the oil pressure drops, the pilot **will** declare an emergency."\n\n**Type 2 \u2014 Hypothetical (present/future)**\nIf + past simple, would/could + base verb\n\u2192 "If the engine **failed**, the crew **would** follow the ECAM."\n\n**Type 3 \u2014 Impossible (past)**\nIf + past perfect, would/could + have + past participle\n\u2192 "If the crew **had noticed** the leak, they **would have** diverted."',null,null,null)
B.KW=new A.aJ("If the fuel quantity drops below minimum, the aircraft must return to base.","Yak\u0131t miktar\u0131 minimumun alt\u0131na d\xfc\u015ferse u\xe7ak \xfcsse d\xf6nmelidir.","If the fuel quantity drops")
B.LU=new A.aJ("If the hydraulic system were to fail, the pilot would use backup controls.","Hidrolik sistem ar\u0131za yapsa pilot yedek kontrolleri kullan\u0131rd\u0131.","were to fail")
B.KT=new A.aJ("If maintenance had been performed on time, the fault would not have occurred.","Bak\u0131m zaman\u0131nda yap\u0131lsayd\u0131 ar\u0131za meydana gelmezdi.","had been performed")
