B.SE=new A.V(B.aj,"Hava durumu havac\u0131l\u0131k i\xe7in kritiktir","Hava raporlar\u0131 ve navigasyon belgeleri y\xfcksek d\xfczeyde standardize edilmi\u015f kelime bilgisi kullan\u0131r. METAR, TAF, NOTAM ve ATIS, pilotlar\u0131n ve kontrol\xf6rlerin aninda anlamas\u0131 gereken belirli terimler i\xe7erir.\n\nBu ders, en s\u0131k s\u0131nanan hava durumu ve navigasyon terimlerini kapsar.",null,null,null)
