B.R9=new A.V(B.aj,"ATIS kritik u\xe7u\u015f \xf6ncesi bilgileri sunar","ATIS (Otomatik Terminal Bilgi Servisi) g\xfcncel havaliman\u0131 bilgilerini kesintisiz yay\u0131nlar. Pilotlar ATC ile temasa ge\xe7meden \xf6nce g\xfcncel ATIS bilgisini almal\u0131 ve ATIS harfiyle (Alfa, Bravo, Charlie\u2026) ald\u0131klar\u0131n\u0131 teyit etmelidir.\n\nOkuma anlama sorular\u0131 \xe7o\u011funlukla ATIS tarz\u0131 metinler kullanarak belirli bilgileri \xe7\u0131karman\u0131z\u0131 ister.",null,null,null)
B.RP=new A.V(B.B,"\ud83d\udcfb Standart ATIS \u0130\xe7eri\u011fi",'Bir ATIS yay\u0131n\u0131 \u015fu s\u0131rayla bilgileri i\xe7erir:\n1. Havaliman\u0131 ad\u0131 ve ATIS bilgi harfi\n2. G\xf6zlem saati\n3. Kullan\u0131lan aktif pist(ler)\n4. Kullan\u0131lan yakla\u015fma tipi (ILS/VOR/Visual)\n5. R\xfczgar y\xf6n\xfc ve h\u0131z\u0131\n6. G\xf6r\xfc\u015f\n7. Hava olaylar\u0131\n8. Bulut katmanlar\u0131\n9. S\u0131cakl\u0131k ve \xe7i\u011f noktas\u0131\n10. QNH\n11. NOTAM\'lar/\xf6zel duyurular\n12. "Advise on initial contact you have information [letter]"',null,null,null)
B.LB=new A.aJ("Istanbul Atat\xfcrk information Alpha. Time 0650 UTC. Runway in use: 36L for landing, 36R for takeoff.","\u0130stanbul Atat\xfcrk, bilgi Alfa. Saat 0650 UTC. Kullan\u0131lan pist: ini\u015f i\xe7in 36L, kalk\u0131\u015f i\xe7in 36R.","information Alpha")
B.L2=new A.aJ("ILS approach in use for runway 36L. Transition level: FL60.","Pist 36L i\xe7in ILS yakla\u015fmas\u0131 kullan\u0131lmaktad\u0131r. Ge\xe7i\u015f seviyesi: FL60.","Transition level")
