B.S1=new A.V(B.aj,"Havac\u0131l\u0131k raporlar\u0131nda dolayl\u0131 anlat\u0131m","Havac\u0131l\u0131k olay ve kaza raporlar\u0131, m\xfcrettebat \xfcyelerinin veya kontrol\xf6rlerin **s\xf6ylediklerini** veya **d\xfc\u015f\xfcnd\xfcklerini** s\u0131k\xe7a aktar\u0131r. Bu ifadeleri aktarmak i\xe7in kullan\u0131lan dilbilgisi yap\u0131s\u0131na **dolayl\u0131/aktarmal\u0131 anlat\u0131m** denir.\n\nS\u0131nav sorular\u0131 \xe7o\u011funlukla do\u011frudan anlat\u0131m\u0131 dolayl\u0131ya \xe7evirmenizi ya da dolayl\u0131 anlat\u0131m c\xfcmlesini do\u011fru tamamlaman\u0131z\u0131 ister.",null,null,null)
B.QE=new A.V(B.f0,"Zaman kaymas\u0131n\u0131 izle",null,null,B.rj,null)
B.Qp=new A.V(B.B,"Zaman Kaymas\u0131 Kural\u0131",'Aktar\u0131m fiili **ge\xe7mi\u015f zaman** oldu\u011funda (said, told, reported), zamanlar geri kayar:\n\n| Do\u011frudan | Dolayl\u0131 Anlat\u0131m |\n|---|---|\n| is/am/are | **was/were** |\n| was/were | **had been** |\n| will | **would** |\n| can | **could** |\n| must | **had to** |\n| has/have + V3 | **had** + V3 |\n\n"The system **is** malfunctioning." \u2192\nPilot, sistemin **was** malfunctioning oldu\u011funu s\xf6yledi.',null,null,null)
B.KZ=new A.aJ("The captain reported that the hydraulic pressure had dropped below limits.","Kaptan, hidrolik bas\u0131nc\u0131n limitin alt\u0131na d\xfc\u015ft\xfc\u011f\xfcn\xfc bildirdi.","had dropped")
B.LZ=new A.aJ("ATC informed the crew that the runway was temporarily closed.","ATC ekibe pistin ge\xe7ici olarak kapat\u0131ld\u0131\u011f\u0131n\u0131 bildirdi.","was temporarily closed")
B.LG=new A.aJ("The maintenance engineer said he would complete the inspection by 0600.","Bak\u0131m m\xfchendisi incelemeyi 06:00'ya kadar tamamlayaca\u011f\u0131n\u0131 s\xf6yledi.","would complete")
