B.QZ=new A.V(B.aj,"Resmi havac\u0131l\u0131k belgelerinin \xf6zel dil kal\u0131plar\u0131 vard\u0131r","Operasyon k\u0131lavuzlar\u0131, bak\u0131m k\u0131lavuzlar\u0131 (AMM) ve u\xe7u\u015fa elveri\u015flilik direktifleri, kesin hukuki ve teknik \xe7\u0131kar\u0131mlar i\xe7eren resmi \u0130ngilizce kullan\u0131r. Bu d\xfczeydeki \xe7eviri sorular\u0131, yaln\u0131zca kelimeleri de\u011fil, arkar\u0131ndaki **d\xfczenleyici amac\u0131** da anlamay\u0131 gerektirir.",null,null,null)
B.SL=new A.V(B.B,"\ud83d\udcd5 D\xfczenleyici Dil","**Shall** \u2014 mandatory requirement (legal obligation in ICAO documents)\n**Should** \u2014 recommended practice (not legally binding, but expected)\n**May** \u2014 permitted (optional)\n**Must** \u2014 mandatory (operational context, not formal ICAO legal text)\n\n**Compliance** \u2014 acting in accordance with a regulation\n**In accordance with (IAW)** \u2014 following specified requirements\n**Subject to** \u2014 conditional upon something\n**Notwithstanding** \u2014 despite; even though\n**Hereinafter** \u2014 from this point forward in the document",null,null,null)
B.L8=new A.aJ("All maintenance shall be carried out by qualified personnel in accordance with the approved data.","T\xfcm bak\u0131m i\u015flemleri, onayl\u0131 veriye uygun olarak nitelikli personel taraf\u0131ndan yap\u0131lmal\u0131d\u0131r.","shall be carried out")
B.L_=new A.aJ("Subject to operational requirements, the interval may be extended by not more than 10 flight hours.","Operasyonel gerekliliklere ba\u011fl\u0131 olarak, interval en fazla 10 u\xe7u\u015f saati uzat\u0131labilir.","Subject to")
B.L3=new A.aJ("Notwithstanding the above, the captain retains full authority over the safe conduct of the flight.","Yukar\u0131dakilerle birlikte, kaptan u\xe7u\u015fun g\xfcvenli y\xfcr\xfct\xfclmesi konusunda tam yetkisini korur.","Notwithstanding")
B.W9=s([B.L8,B.L_,B.L3],t.l)
B.QW=new A.V(B.ak,"K\u0131lavuz Dili \xd6rnekleri",null,B.W9,null,null)
B.RY=new A.V(B.al,"\u2708\ufe0f \xc7eviri \u0130pu\xe7lar\u0131",'\xd6nemli \xe7eviri ayr\u0131mlar\u0131:\n\u2022 ICAO belgelerinde "**shall**" \u2260 "will" (gelecek) \u2014 **zorunlu** anlam\u0131na gelir\n\u2022 "**notwithstanding**" \u2260 "noting" \u2014 **ra\u011fmen** veya **ne olursa olsun** anlam\u0131na gelir\n\u2022 "**in the event of**" = "e\u011fer \u2026 olursa/durumunda" (\u015fartl\u0131)\n\u2022 "**prior to**" = "\u2026dan \xf6nce" (before ifadesinin resmi hali)\n\u2022 "**subsequent to**" = "\u2026dan sonra" (after ifadesinin resmi hali)',null,null,null)
