B.SX=new A.V(B.aj,"Acil durum dili kesin olmal\u0131d\u0131r","Acil durum ileti\u015fimleri ICAO ifade kurallar\u0131na uyar. C\xfcmle tamamlama sorular\u0131nda, c\xfcmlenin anlam\u0131n\u0131 **tam ve eksiksiz** dolduran kelime ya da ifadeyi se\xe7meniz gerekir.\n\nYanl\u0131\u015f se\xe7enekler \xe7o\u011funlukla mant\u0131kl\u0131 g\xf6r\xfcn\xfcr \u2014 anahtar, en **do\u011fru** havac\u0131l\u0131k terimini se\xe7mektir.",null,null,null)
