B.Rm=new A.V(B.B,"\ud83d\udce1 Acil Durum Kontrol Listesi Dili",'Acil durum kontrol listeleri \xf6zel c\xfcmle kal\u0131plar\u0131 kullan\u0131r:\n\u2022 "In the event of \u2026\u2026\u2026\u2026, the crew should\u2026"\n\u2022 "If \u2026\u2026\u2026\u2026 is observed, immediately\u2026"\n\u2022 "\u2026\u2026\u2026\u2026\u2026 and report to ATC"\n\u2022 "Declare \u2026\u2026\u2026\u2026\u2026 and request priority landing"\n\nYayg\u0131n fiiller: **declare, squawk, divert, dump, depressurize, evacuate, report**',null,null,null)
B.Lq=new A.aJ("In the event of an engine fire, the crew must __________ the affected engine.","Motor yang\u0131n\u0131 durumunda, ekip etkilenen motoru kapatmal\u0131d\u0131r.","shut down")
