B.Rh=new A.V(B.aj,"\u0130leri metinler karma\u015f\u0131k dilbilgisi yap\u0131lar\u0131 kullan\u0131r","Havac\u0131l\u0131k belgeleri, kaza raporlar\u0131 ve ICAO yay\u0131nlar\u0131, birden fazla yan c\xfcmleyi bir araya getiren karma\u015f\u0131k c\xfcmle yap\u0131lar\u0131 kullan\u0131r. \u0130leri d\xfczeyde, hem anlama hem de \xfcretim sorular\u0131nda bunlar\u0131 do\u011fru bir \u015fekilde ele almal\u0131s\u0131n\u0131z.",null,null,null)
B.Qu=new A.V(B.B,"S\u0131fat C\xfcmleleri",'**Defining** (no commas): identifies which one\n\u2192 "The component **that failed** was the hydraulic pump."\n\n**Non-defining** (with commas): adds extra information\n\u2192 "The hydraulic pump, **which had just been serviced**, failed."\n\n**Reduced relative clause** (participle phrase):\n\u2192 "The pilot **flying the aircraft** reported vibration." (= who was flying)\n\u2192 "The component **installed last week** is defective." (= that was installed)',null,null,null)
B.Rg=new A.V(B.B,"Orta\xe7 \u0130fadeleri & Devrik Yap\u0131",'**Present participle** (active, simultaneous):\n\u2192 "**Having received** the clearance, the crew began the takeoff roll."\n\n**Past participle** (passive, completed first):\n\u2192 "**Notified by ATC**, the pilot diverted to the alternate."\n\n**Negative inversion** (formal/reports):\n\u2192 "**Under no circumstances should** the aircraft depart without a clearance."\n\u2192 "**Not until the checks were completed** did the captain approve departure."',null,null,null)
B.M6=new A.aJ("The maintenance technician, having completed all required inspections, signed the aircraft log.","Bak\u0131m teknisyeni, gerekli t\xfcm denetimleri tamamlad\u0131ktan sonra u\xe7ak k\xfct\xfc\u011f\xfcn\xfc imzalad\u0131.","having completed")
B.M4=new A.aJ("Under no circumstances should flight crew members operate the aircraft beyond approved limits.","U\xe7u\u015f ekibi \xfcyeleri hi\xe7bir ko\u015fulda u\xe7a\u011f\u0131 onaylanan limitler d\u0131\u015f\u0131nda kullanmamal\u0131d\u0131r.","Under no circumstances should")
