B.SR=new A.V(B.al,"\u2708\ufe0f S\u0131nav \u0130pucu",'S\u0131nav sorular\u0131nda devrik yap\u0131 i\u015faretleri:\n\u2022 "Under no circumstances\u2026" \u2192 yard\u0131mc\u0131 fiil \xf6zneden \xf6nce gelmelidir\n\u2022 "Not until\u2026" \u2192 ana c\xfcmlede did/could \xf6zneden \xf6nce gelir\n\u2022 "Only after\u2026" \u2192 ana c\xfcmlede devrik yap\u0131\n\nOrta\xe7 ifadeler \u2014 \xf6zneyi kontrol edin:\n\u2022 "**Having landed**, the aircraft was directed to the gate." \u2713 (aircraft indi)\n\u2022 "**Having landed**, the gate was assigned." \u2717 (gate inmedi \u2014 sarkan orta\xe7)',null,null,null)
