B.Sg=new A.V(B.aj,"Kaza raporlar\u0131 kesin hukuki ve teknik dil kullan\u0131r","ICAO Ek 13 kaza ara\u015ft\u0131rma raporlar\u0131, havac\u0131l\u0131ktaki en dilbilimsel a\xe7\u0131dan zorlay\u0131c\u0131 belgeler aras\u0131ndad\u0131r. Tek bir metinde hukuki kesinli\u011fi, edilgen yap\u0131lar\u0131, teknik do\u011frulu\u011fu ve nedensellik analizini bir araya getirirler.\n\nBu raporlardan \xe7eviri sorular\u0131, hem teknik anlam\u0131 hem de her ifadenin hukuki sonu\xe7lar\u0131n\u0131 anlamay\u0131 gerektirir.",null,null,null)
B.Rf=new A.V(B.B,"\u26a0\ufe0f Nedensellik Dili",'**Probable cause** \u2014 the primary factor judged to have produced the accident\n**Contributing factor** \u2014 a condition that increased risk but was not the primary cause\n**Causal factor** \u2014 any element in the cause chain\n\nCausal verbs and phrases:\n\u2022 "**led to**" = caused/resulted in (direct chain)\n\u2022 "**attributed to**" = judged as the cause\n\u2022 "**resulted in**" = produced this outcome\n\u2022 "**was a factor in**" = contributed but not sole cause\n\u2022 "**was consistent with**" = evidence matches this explanation',null,null,null)
B.SM=new A.V(B.B,"\ud83d\udccb Soru\u015fturma Bulgular\u0131 Dili",'"The investigation **found** that\u2026" \u2192 formal finding\n"Evidence **indicated** that\u2026" \u2192 supported but not proven\n"**It could not be determined** whether\u2026" \u2192 insufficient evidence\n"The crew **failed to**\u2026" \u2192 did not perform required action\n"**Contrary to** the standard operating procedure\u2026" \u2192 SOP violation\n"The accident **is survivable** / **was not survivable**" \u2192 survivability finding\n"**Safety recommendation**" \u2192 formal advisory to prevent recurrence',null,null,null)
B.M7=new A.aJ("The probable cause of the accident was the crew's failure to monitor fuel quantity.","Kazan\u0131n muhtemel nedeni, ekibin yak\u0131t miktar\u0131n\u0131 izlememesiydi.","probable cause")
B.LI=new A.aJ("It could not be determined whether the crew had received the updated weather information.","Ekibin g\xfcncellenmi\u015f hava durumu bilgisini al\u0131p almad\u0131\u011f\u0131 belirlenemedi.","It could not be determined")
B.M5=new A.aJ("The investigation attributed the loss of situational awareness to crew fatigue and inadequate CRM.","Soru\u015fturma, durum fark\u0131ndal\u0131\u011f\u0131n\u0131n kayb\u0131n\u0131 m\xfcrettebat yorgunlu\u011funa ve yetersiz EKY'ye ba\u011flad\u0131.","attributed to")
B.Zy=s([B.M7,B.LI,B.M5],t.l)
B.RH=new A.V(B.ak,"Rapor Metni \xd6rnekleri",null,B.Zy,null,null)
B.T0=new A.V(B.al,"\u2708\ufe0f \xc7eviri S\u0131nav Stratejisi",'Kaza raporu \xe7eviri sorular\u0131 i\xe7in:\n\u2022 "**Probable cause**" \u2260 "possible cause" \u2014 tespit edilen EN MUHTEMEL nedendir\n\u2022 "**Contributing factor**" \u2260 "main reason" \u2014 ikincil, a\u011f\u0131rla\u015ft\u0131r\u0131c\u0131 bir ko\u015fuldur\n\u2022 "**Crew failed to**" = zorunlu bir eylem yap\u0131lmad\u0131 \u2014 do\u011frudan ihmal anlam\u0131 ta\u015f\u0131maz\n\u2022 "**It could not be determined**" = yetersiz kan\u0131t \u2014 "bilinmiyor" olarak \xe7evirmeyin\n\u2022 "**Contrary to SOP**" = prosed\xfcr ihlali \u2014 raporlarda her zaman ciddidir',null,null,null)
B.YT=s(["The accident was caused by an out-of-control aircraft hitting terrain","The aircraft was in controlled flight when it struck terrain","The crew controlled the aircraft into terrain intentionally","The terrain was controlled by ATC when the accident occurred"],t.s)
B.a4R=new A.ad(-300,B.bc,460,'"The accident was attributed to controlled flight into terrain." This means:',B.YT,1,B.A,null,null,null)
B.YG=s(["In accordance with SOPs","Violating or not following SOPs","Similar to SOPs in other companies","An improvement over SOPs"],t.s)
B.a4B=new A.ad(-301,B.bc,461,'"Contrary to standard operating procedures" means:',B.YG,1,B.A,null,null,null)
B.Yy=s(["The main cause was crew rest","Crew rest was one element that made the accident more likely","Crew rest alone caused the accident","The crew rested adequately"],t.s)
B.a4w=new A.ad(-302,B.bc,462,'"A contributing factor was the inadequate crew rest period." This means:',B.Yy,1,B.A,null,null,null)
B.Vc=s(["It is confirmed that","There was not enough evidence to establish","It is unlikely that","The investigation did not examine"],t.s)
B.a4g=new A.ad(-303,B.bc,463,'"It could not be determined whether\u2026" in a report means:',B.Vc,1,B.b3,null,null,null)
B.Yo=s([B.a4R,B.a4B,B.a4w,B.a4g],t.C)
B.Sn=new A.V(B.ad,"Pratik Sorular",null,null,null,B.Yo)
B.Ws=s([B.Sg,B.Rf,B.SM,B.RH,B.T0,B.Sn],t.q)
B.PS=new A.ch("translation_4","Kaza Soru\u015fturma Raporlar\u0131","ICAO Ek 13 soru\u015fturma dilini \xe7evirme","translation","\ud83d\udcf0",B.Ws)
B.S5=new A.V(B.aj,"ADs are mandatory safety compliance documents","U\xe7u\u015fa Elveri\u015flilik Direktifi (AD), belirli bir u\xe7ak tipindeki g\xfcvenli olmayan bir durumu gidermek amac\u0131yla sivil havac\u0131l\u0131k otoritesi taraf\u0131ndan zorunlu eylem gerektiren yasal ba\u011flay\u0131c\u0131 bir belgedir. Uyumsuzluk yasad\u0131\u015f\u0131d\u0131r ve i\u015fletme sertifikas\u0131n\u0131n ask\u0131ya al\u0131nmas\u0131na yol a\xe7abilir.\n\nAD dili havac\u0131l\u0131ktaki en kesin d\xfczenleyici dildir \u2014 her kelimenin yasal a\u011f\u0131rl\u0131\u011f\u0131 vard\u0131r.",null,null,null)
B.RF=new A.V(B.B,"\ud83d\udcdc AD Yap\u0131s\u0131",'Tipik bir AD \u015funlar\u0131 i\xe7erir:\n1. **Uygulanabilirlik** \u2014 hangi u\xe7ak/motor/par\xe7alar etkileniyor\n2. **G\xfcvensiz durum** \u2014 \xe7\xf6z\xfclecek tehlike\n3. **Gerekli eylem** \u2014 ne yap\u0131lmas\u0131 gerekiyor\n4. **Uyumluluk s\xfcresi** \u2014 ne zamana kadar yap\u0131lmal\u0131 (\xf6r. "50 u\xe7u\u015f saati i\xe7inde")\n5. **Y\xf6ntem** \u2014 nas\u0131l uyulur (servis b\xfclteni, \xf6zel prosed\xfcr)\n6. **Alternatif Uyumluluk Y\xf6ntemi (AMOC)** \u2014 onaylanm\u0131\u015f alternatif\n7. **Maliyetler** \u2014 tahmini uyumluluk maliyeti',null,null,null)
B.SY=new A.V(B.B,"\u26a0\ufe0f Uyumluluk S\xfcresi Dili",'**"Within 50 flight hours after the effective date"** \u2014 must be done before 50 more hours\n**"At the next scheduled maintenance"** \u2014 at next A/B/C check\n**"Before further flight"** \u2014 aircraft must not fly until complied with\n**"At first opportunity"** \u2014 as soon as practical (not as urgent as "before further flight")\n**"Repetitive inspection every 200 FH"** \u2014 not a one-time action; must be repeated\n**"Terminating action"** \u2014 permanently satisfies the AD (no more repetitive checks needed)',null,null,null)
B.KP=new A.aJ("This AD requires repetitive inspections of the fuselage skin every 500 flight cycles.","Bu AD, her 500 u\xe7u\u015f \xe7evriminde g\xf6vde kaplamas\u0131n\u0131n tekrarl\u0131 denetimlerini gerektirmektedir.","repetitive inspections")
B.LF=new A.aJ("The applicability of this AD extends to all Boeing 737-800 aircraft with serial numbers 35201 through 41234.","Bu AD'nin uygulanabilirli\u011fi, 35201 ile 41234 aras\u0131ndaki seri numaralar\u0131na sahip t\xfcm Boeing 737-800 u\xe7aklar\u0131n\u0131 kapsamaktad\u0131r.","applicability")
B.KR=new A.aJ("Compliance is required before further flight after the effective date.","Y\xfcr\xfcrl\xfck tarihinden sonra daha fazla u\xe7u\u015ftan \xf6nce uyum zorunludur.","before further flight")
B.Zz=s([B.KP,B.LF,B.KR],t.l)
B.Sf=new A.V(B.ak,"AD Dili \xd6rnekleri",null,B.Zz,null,null)
B.SB=new A.V(B.al,"\u2708\ufe0f \u0130leri Okuma Stratejisi",'AD okuma anlama sorular\u0131 i\xe7in:\n\u2022 **Uygulanabilirlik** b\xf6l\xfcm\xfc hangi u\xe7aklar\u0131n etkilendi\u011fini s\xf6yler \u2014 bunu \xf6nce kontrol edin\n\u2022 "**Before further flight**" = en acil uyumluluk s\xfcresi \u2014 u\xe7ak YER\'DE KALMALIDIR\n\u2022 "**Terminating action**" = bir kez yap\u0131ld\u0131\u011f\u0131nda tekrar edici denetim gerekmez\n\u2022 **AMOC** = alternatif uyumluluk y\xf6ntemi \u2014 otorite taraf\u0131ndan onaylanmal\u0131d\u0131r\n\u2022 "**At the next scheduled**" "iste\u011fe ba\u011fl\u0131" anlam\u0131na gelmez \u2014 o noktada zorunludur\n\u2022 Tarihlere dikkat edin: "after the effective date" ile "from the date of manufacture"',null,null,null)
B.Zq=s(["All Airbus A320 variants","A320-200 with serial numbers 3001\u20135500","A320-200 manufactured after the effective date","All Airbus narrowbody aircraft"],t.s)
B.a3N=new A.ad(-310,B.az,650,"Which aircraft are affected by this AD?",B.Zq,1,B.P,null,null,null)
B.ZC=s(["Every 100 flight cycles","Once only","Every 500 flight cycles","At every annual check"],t.s)
B.a42=new A.ad(-311,B.az,651,"How often must the repetitive inspection be performed?",B.ZC,2,B.P,null,null,null)
B.Vk=s(["Performing 10 consecutive inspections with no findings","Replacing the frame assembly with Part Number A320-FR-9902","Operating the aircraft for 5,000 flight cycles","Obtaining an AMOC from the authority"],t.s)
