B.YM=s(["Before the next annual check","Within 100 flight cycles after the effective date","Before the next 500 flight cycles","At first opportunity after receiving the AD"],t.s)
B.a3G=new A.ad(-313,B.az,653,"The first inspection must be completed:",B.YM,1,B.P,null,null,null)
